INSERT INTO companies VALUES('22530fe7-5fc8-4a56-8df0-8b57774cfda5','TensorWave','operator','https://tensorwave.com','AMD-focused AI infrastructure provider with fresh capital. Building large-scale GPU clusters using AMD Instinct accelerators.','A','AI Cloud','8,000 AMD Instinct MI325X GPUs in dedicated training cluster. Liquid-cooled. Building world''s largest liquid-cooled AMD GPU deployment. Run-rate revenue target: $100M+ by end of 2025 (20x YoY).','$100M Series A (May 2025) — used for AMD GPU cluster expansion. Magnetar, AMD Ventures, Maverick Silicon, Nexus VP, Prosperity7.',91,'2026-03-21 02:26:32','2026-03-21 02:49:33',NULL,NULL,'$166M+ equity + $800M DDTL debt','{"type":"Series A","amount":"$100M","date":"2025-05","investors":["Magnetar","AMD Ventures","Nexus Venture Partners","Maverick Silicon","Prosperity7 (Aramco-backed)"]}','["Magnetar","AMD Ventures","Nexus Venture Partners","Maverick Silicon","Prosperity7 (Aramco-backed)"]','Las Vegas, NV (primary)',NULL,NULL,NULL,'[{"date":"2025-05-14","headline":"TensorWave Secures $100M Series A Co-Led by Magnetar and AMD Ventures to build world''s largest liquid-cooled AMD GPU deployment","url":"https://tensorwave.com/blog/series-a","category":"funding"},{"date":"2026-01-01","headline":"TensorWave partners with Credo to power next-generation AMD-based AI clusters","url":"https://finance.yahoo.com/news/tensorwave-partners-credo-power-next-140000437.html","category":"partnership"},{"date":"2025-08-01","headline":"TensorWave on track for $100M+ revenue run rate (20x YoY); receives first AMD MI355X shipments","url":"https://www.futuriom.com/articles/news/tensorwave-is-poised-to-be-amds-biggest-advocate/2025/08","category":"product"}]',NULL,'2026-03-21 12:37:02',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'queued');
